What does this program print?

```cpp
#include <iostream>
#include <stdexcept>
struct T {
    T(int i) : id(i) { std::cout << "ctor " << id << "\n"; }
    ~T() { std::cout << "dtor " << id << "\n"; }
    int id;
};
void inner() {
    T a(1);
    throw std::runtime_error("x");
}
void outer() {
    T b(2);
    inner();
}
int main() {
    try { outer(); }
    catch (const std::runtime_error&) { std::cout << "caught\n"; }
    return 0;
}
```

