```cpp
#include <iostream>
#include <stdexcept>
void thrower() {
    std::cout << "A\n";
    throw std::runtime_error("boom");
    std::cout << "B\n";
}
int main() {
    try {
        std::cout << "C\n";
        thrower();
        std::cout << "D\n";
    } catch (const std::runtime_error&) {
        std::cout << "E\n";
    }
    std::cout << "F\n";
    return 0;
}
